import React, { useState } from 'react';
import { Menu, X } from 'lucide-react';

export default function Navbar() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  return (
    <nav className="bg-zinc-900 text-zinc-400 border-b border-zinc-800 font-sans">
      <div className="container mx-auto px-4 py-4 flex justify-between items-center">
        <div className="flex items-center">
          <span className="text-2xl font-bold text-zinc-200 mr-4">CanvasCraft Studio</span>
          <span className="hidden md:block text-sm italic text-zinc-500">
            Showcase your creative journey with elegance and impact.
          </span>
        </div>

        <div className="hidden md:flex space-x-6">
          <a href="#" className="hover:text-zinc-200 transition-colors duration-300">Home</a>
          <a href="#" className="hover:text-zinc-200 transition-colors duration-300">Portfolio</a>
          <a href="#" className="hover:text-zinc-200 transition-colors duration-300">About</a>
          <a href="#" className="hover:text-zinc-200 transition-colors duration-300">Contact</a>
        </div>

        <div className="md:hidden flex items-center">
          <button onClick={toggleMenu} className="text-zinc-400 hover:text-zinc-200 focus:outline-none focus:ring-2 focus:ring-zinc-700 rounded-xl p-2">
            {isMenuOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
