            <a href="#" className="block text-zinc-300 hover:text-zinc-100 transition-colors duration-300">Contact</a>
            <span className="block text-sm italic text-zinc-500 mt-4">
              Showcase your creative journey with elegance and impact.
            </span>
          </div>
        </div>
      )}
    </nav>
  );
}

