      <img src={image} alt={title} className="w-full h-48 md:h-64 lg:h-80 object-cover rounded-xl" />
    </div>
  );
};

const PortfolioSection = () => {
  const [activeTab, setActiveTab] = useState('all');

  const portfolioItems = [
    { title: 'Project 1', description: 'This is a description of project 1', image: 'https://via.placeholder.com/300' },
    { title: 'Project 2', description: 'This is a description of project 2', image: 'https://via.placeholder.com/300' },
    { title: 'Project 3', description: 'This is a description of project 3', image: 'https://via.placeholder.com/300' },
  ];

  const filteredItems = portfolioItems.filter((item) => {
    if (activeTab === 'all') return true;
    return item.title.toLowerCase().includes(activeTab.toLowerCase());
  });

  return (
    <section className="bg-zinc-800 py-12 md:py-16 lg:py-20">
      <div className="container mx-auto px-4 md:px-6 lg:px-8">
        <h1 className="text-zinc-400 text-3xl md:text-4xl lg:text-5xl mb-4">Our Portfolio</h1>
        <div className="flex flex-wrap justify-center mb-8">
          <button
            className={`px-4 py-2 md:px-6 md:py-3 lg:px-8 lg:py-4 text-zinc-400 hover:text-zinc-200 bg-zinc-600 hover:bg-zinc-700 rounded-xl ${
              activeTab === 'all' ? 'bg-zinc-700' : ''
            }`}
            onClick={() => setActiveTab('all')}
          >
            All
          </button>
          <button
            className={`px-4 py-2 md:px-6 md:py-3 lg:px-8 lg:py-4 text-zinc-400 hover:text-zinc-200 bg-zinc-600 hover:bg-zinc-700 rounded-xl ${
              activeTab === 'project1' ? 'bg-zinc-700' : ''
            }`}
            onClick={() => setActiveTab('project1')}
          >
            Project 1
          </button>
          <button
            className={`px-4 py-2 md:px-6 md:py-3 lg:px-8 lg:py-4 text-zinc-400 hover:text-zinc-200 bg-zinc-600 hover:bg-zinc-700 rounded-xl ${
              activeTab === 'project2' ? 'bg-zinc-700' : ''
            }`}
            onClick={() => setActiveTab('project2')}
          >
            Project 2
          </button>
          <button
            className={`px-4 py-2 md:px-6 md:py-3 lg:px-8 lg:py-4 text-zinc-400 hover:text-zinc-200 bg-zinc-600 hover:bg-zinc-700 rounded-xl ${
              activeTab === 'project3' ? 'bg-zinc-700' : ''
            }`}
            onClick={() => setActiveTab('project3')}
          >
            Project 3
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6 lg:gap-8">
          {filteredItems.map((item, index) => (
            <PortfolioItem key={index} title={item.title} description={item.description} image={item.image} />
          ))}
        </div>
      </div>
    </section>
  );
};

export default PortfolioSection;

